export const FORMAT_ICON_XML: Record<string, string> = {
  pdf, docx, doc, ppt, pptx: ppt, xls, xlsx, zip, png, jpeg, jpg,
};

export function formatIconXml(ext: string): string | undefined {
  const e = ext.toLowerCase();
  if (e === "jpeg") return FORMAT_ICON_XML.jpeg;
  return FORMAT_ICON_XML[e];
}
